// And groups predicates with the AND operator between them.
func And(predicates ...predicate.MediaContent) predicate.MediaContent {
	return predicate.MediaContent(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.MediaContent) predicate.MediaContent {
	return predicate.MediaContent(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.MediaContent) predicate.MediaContent {
	return predicate.MediaContent(sql.NotPredicates(p))
}
